     2→/**
     3→ * ManageServer.ts - Observability Dashboard Manager
     4→ *
     5→ * A CLI tool for managing the PAI Observability Dashboard (server + client)
     6→ *
     7→ * Usage:
     8→ *   bun ~/.claude/Observability/Tools/ManageServer.ts <command>
     9→ *
    10→ * Commands:
    11→ *   start     Start the observability dashboard
    12→ *   stop      Stop the observability dashboard
    13→ *   restart   Restart the observability dashboard
    14→ *   status    Check if dashboard is running
    15→ *   logs      Show recent server output
    16→ *   open      Open dashboard in browser
    17→ *
    18→ * @author PAI (Personal AI Infrastructure)
    19→ */
    20→
    21→import { $ } from "bun";
    22→import { existsSync } from "fs";
    23→import { join } from "path";
    24→
    25→const CONFIG = {
    26→  basePath: join(process.env.HOME || "", ".claude/Observability"),
    27→  serverPort: 4000,
    28→  clientPort: 5172,
    29→  logFile: join(process.env.HOME || "", "Library/Logs/pai-observability.log"),
    30→};
    31→
    32→const colors = {
    33→  green: (s: string) => `\x1b[32m${s}\x1b[0m`,
    34→  red: (s: string) => `\x1b[31m${s}\x1b[0m`,
    35→  yellow: (s: string) => `\x1b[33m${s}\x1b[0m`,
    36→  blue: (s: string) => `\x1b[34m${s}\x1b[0m`,
    37→  dim: (s: string) => `\x1b[2m${s}\x1b[0m`,
    38→  bold: (s: string) => `\x1b[1m${s}\x1b[0m`,
    39→};
    40→
    41→async function isPortInUse(port: number): Promise<boolean> {
    42→  try {
    43→    const result = await $`lsof -Pi :${port} -sTCP:LISTEN -t`.quiet().nothrow();
    44→    return result.exitCode === 0;
    45→  } catch {
    46→    return false;
    47→  }
    48→}
    49→
    50→async function isServerHealthy(): Promise<boolean> {
    51→  try {
    52→    const response = await fetch(`http://localhost:${CONFIG.serverPort}/events/filter-options`);
    53→    return response.ok;
    54→  } catch {
    55→    return false;
    56→  }
    57→}
    58→
    59→async function isClientHealthy(): Promise<boolean> {
    60→  try {
    61→    const response = await fetch(`http://localhost:${CONFIG.clientPort}`);
    62→    return response.ok;
    63→  } catch {
    64→    return false;
    65→  }
    66→}
    67→
    68→async function startServer(): Promise<void> {
    69→  const serverRunning = await isPortInUse(CONFIG.serverPort);
    70→  const clientRunning = await isPortInUse(CONFIG.clientPort);
    71→
    72→  if (serverRunning && clientRunning) {
    73→    console.log(colors.yellow("Observability dashboard already running."));
    74→    console.log(colors.bold(`URL: http://localhost:${CONFIG.clientPort}`));
    75→    return;
    76→  }
    77→
    78→  if (serverRunning || clientRunning) {
    79→    console.log(colors.yellow("Partial state detected. Cleaning up..."));
    80→    await stopServer();
    81→  }
    82→
    83→  console.log(colors.blue("Starting observability dashboard..."));
    84→
    85→  // Start server
    86→  const serverCmd = `cd "${CONFIG.basePath}/apps/server" && nohup bun run dev >> "${CONFIG.logFile}" 2>&1 &`;
    87→  await $`sh -c ${serverCmd}`.quiet();
    88→
    89→  // Wait for server
    90→  for (let i = 0; i < 15; i++) {
    91→    await Bun.sleep(500);
    92→    if (await isServerHealthy()) break;
    93→  }
    94→
    95→  if (!await isServerHealthy()) {
    96→    console.error(colors.red("Server failed to start. Check logs."));
    97→    process.exit(1);
    98→  }
    99→
